// Cycle the X queue one post per run. Text-only, link-free by design:
// external links cost 30-50% reach on X (2026). Threads with links go out
// manually from marketing/repurposed/ bundles with the URL in Reply 1.
const X_CHANNEL_ID = '6a47b8035ab6d2f1069def94';
const data = $input.first().json;
const posts = (data && data.posts) || [];
if (!posts.length) { throw new Error('x_queue.json empty'); }

const store = $getWorkflowStaticData('global');
let idx = typeof store.xIdx === 'number' ? store.xIdx : 0;
if (idx >= posts.length) idx = 0;
const post = posts[idx];
store.xIdx = idx + 1;

const query = 'mutation Create($input: CreatePostInput!) { createPost(input: $input) { __typename ... on PostActionSuccess { post { id } } ... on MutationError { message } } }';
const input = {
  text: String(post.text).slice(0, 275),
  channelId: X_CHANNEL_ID,
  schedulingType: 'automatic',
  mode: 'addToQueue',
};
return [{ json: { channel: 'x', postId: post.id, graphqlBody: { query, variables: { input } } } }];
